const body = $json.body ?? $json;
const eventType = (body.type ?? 'unknown').toString().toLowerCase();

let nextAction = 'coach_reply';
let coachReply = 'Message recu. Le guide pedagogique prepare une reponse detaillee.';

if (eventType === 'exercise_submission') {
  nextAction = 'exercise_review';
  coachReply = 'Exercice recu. Analyse technique et artistique en cours.';
} else if (eventType === 'chat_message') {
  nextAction = 'micro_coaching';
  coachReply = 'Question recue. Voici une piste: avancez pas a pas et testez sur une image concrete.';
} else if (eventType === 'course_proposal') {
  nextAction = 'curriculum_triage';
  coachReply = 'Proposition pedagogique enregistree. Elle passe en priorisation communautaire.';
}

return [{
  json: {
    status: 'accepted',
    session: 'pedago',
    eventType,
    nextAction,
    coachReply,
    receivedAt: new Date().toISOString(),
    raw: body
  }
}];
